(function animateFavicon() {
    const FRAME_COUNT = 94;
    const FRAME_INTERVAL_MS = 40; // ~25 fps

    // 1. Grab the initial working favicon tag generated by Jekyll
    const initialFavicon = document.getElementById('favicon');
    if (!initialFavicon) return;

    // 2. Extract the absolute directory path dynamically
    const currentHref = initialFavicon.href;
    const baseDir = currentHref.substring(0, currentHref.lastIndexOf('/') + 1);

    // 3. Populate the frame URLs array using the clean base directory path
    const frameUrls = [];
    for (let i = 1; i <= FRAME_COUNT; i++) {
        frameUrls.push(`${baseDir}j_${i}.gif`);
    }

    // 4. Preload frames in the background to eliminate flicker
    frameUrls.forEach(src => { 
        const img = new Image(); 
        img.src = src; 
    });

    let frameIndex = 0;

    // 5. Run the rotation engine
    setInterval(() => {
        const link = document.getElementById('favicon');
        if (link) {
            link.href = frameUrls[frameIndex];
        }
        frameIndex = (frameIndex + 1) % FRAME_COUNT;
    }, FRAME_INTERVAL_MS);
})();
